let cancelReason = null;

if (String(input.request_status || '') !== 'initial_sent') {
  canSendReminder = false;
  cancelReason = 'request_not_initial_sent';
} else if (String(input.waiting_for || '') !== 'OWNER') {
  canSendReminder = false;
  cancelReason = 'conversation_not_waiting_for_owner';
} else if (String(input.request_selected_finca_id || '') !== String(input.conversation_selected_finca_id || '')) {
  canSendReminder = false;
  cancelReason = 'selected_finca_changed';
} else if (input.owner_response !== null && input.owner_response !== undefined) {
  const hasOwnerResponse =
    typeof input.owner_response === 'object'
      ? Object.keys(input.owner_response || {}).length > 0
      : String(input.owner_response).trim() !== '';
  if (hasOwnerResponse) {
    canSendReminder = false;
    cancelReason = 'owner_response_already_present';
  }
} else if (input.agente_activo === false) {
  canSendReminder = false;
  cancelReason = 'bot_disabled';
}

return [
  {
    json: {
      ...input,
      can_send_reminder: canSendReminder,
      cancel_reason: cancelReason,
    },
  },
];

const input = $json || {};
const compact = (value) => String(value ?? '').trim();
const normalizePhone = (value) => {
  const digits = String(value || '').replace(/\D+/g, '').trim();
  if (!digits) return '';
  if (digits.startsWith('57') && digits.length === 12) return '+' + digits;
  if (digits.length === 10) return '+57' + digits;
  return '+' + digits;
};
const sourceIdForPhone = (value) => String(value || '').replace(/\D+/g, '').trim();
const parseNumber = (value) => {
  const num = Number(value);
  return Number.isFinite(num) && num > 0 ? num : null;
};
const templateName = compact(input.template_name || input.reminder_template_name || input.payload?.template_name || input.payload?.reminder_template_name);
const templateLanguage = compact(input.payload?.reminder_template_language || input.template_language || 'en') || 'es_CO';
const fincaName = compact(input.selected_finca_name || input.payload?.selected_finca_name || input.selected_finca_id || 'la finca');
const fechaInicioText = compact(input.fecha_inicio_text || input.payload?.fecha_inicio_text || input.payload?.fecha_inicio || 'Sin dato');
const fechaFinText = compact(input.fecha_fin_text || input.payload?.fecha_fin_text || input.payload?.fecha_fin || 'Sin dato');
const recipientPhone = normalizePhone(input.recipient_phone);
const ownerInboxName = compact(input.owner_chatwoot_inbox_name || input.payload?.owner_chatwoot_inbox_name || "Agent_propietarios") || "Agent_propietarios";
const ownerInboxPhone = normalizePhone(input.owner_chatwoot_inbox_phone || input.payload?.owner_chatwoot_inbox_phone || "+573105639334");
const chatwootBaseUrl = "https://chatwoot-9qe1j-u48275.vm.elestio.app";
const chatwootAccountId = "1";
const chatwootApiToken =
  (typeof process !== 'undefined' && process?.env?.CHATWOOT_API_TOKEN)
    ? String(process.env.CHATWOOT_API_TOKEN).trim()
    : "__CHATWOOT_API_TOKEN__";

let responseStatus = null;
let responseBody = null;
let providerMessageId = null;
let errorMessage = null;
let ownerChatwootInboxId = parseNumber(input.owner_chatwoot_inbox_id || input.payload?.owner_chatwoot_inbox_id);
let ownerChatwootContactId = parseNumber(input.owner_chatwoot_contact_id || input.payload?.owner_chatwoot_contact_id);
let ownerChatwootConversationId = parseNumber(input.owner_chatwoot_conversation_id || input.payload?.owner_chatwoot_conversation_id);
let ownerChatwootMessageId = null;
let ownerChatwootSourceId = compact(input.owner_chatwoot_source_id || input.payload?.owner_chatwoot_source_id) || sourceIdForPhone(recipientPhone);

const helperRequest =
  typeof $httpRequest === 'function'
    ? $httpRequest
    : typeof this !== 'undefined' && this?.helpers?.httpRequest
      ? this.helpers.httpRequest.bind(this.helpers)
      : null;

async function chatwootApi(pathname, method = 'GET', body = null, query = null) {
  if (!helperRequest) throw new Error('http_request_helper_unavailable');
  const normalizedBase = compact(chatwootBaseUrl).replace(/\/+$/, '');
  const normalizedPath = String(pathname || '').startsWith('/') ? String(pathname || '') : `/${String(pathname || '')}`;
  const queryParts = [];
  if (query && typeof query === 'object') {
    for (const [key, value] of Object.entries(query)) {
      if (value === undefined || value === null || value === '') continue;
      queryParts.push(`${encodeURIComponent(String(key))}=${encodeURIComponent(String(value))}`);
    }
  }
  const url = queryParts.length
    ? `${normalizedBase}${normalizedPath}?${queryParts.join('&')}`
    : `${normalizedBase}${normalizedPath}`;
  const response = await helperRequest({
    url,
    method,
    headers: {
      api_access_token: chatwootApiToken,
      Accept: 'application/json',
      ...(body ? { 'Content-Type': 'application/json' } : {}),
    },
    body,
    json: true,
    timeout: 30000,
    ignoreHttpStatusErrors: true,
    returnFullResponse: true,
  });
  const status = Number(response.statusCode || response.status || 0) || 0;
  const raw = response.body;
  const parsed =
    raw && typeof raw === 'object'
      ? raw
      : raw == null
        ? null
        : { raw: String(raw) };
  return { status, body: parsed };
}

