  const normalizedTarget = normalizePhone(targetPhone);
  return ((payload || {}).payload || []).filter((item) => normalizePhone(item?.phone_number || '') === normalizedTarget);
}

async function findInbox() {
  const response = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/inboxes`);
  if (response.status >= 300) {
    throw new Error(`owner_inbox_lookup_failed:${response.status}`);
  }
  const normalizedPhone = normalizePhone(ownerInboxPhone);
  const payload = (response.body || {}).payload || [];
  for (const inbox of payload) {
    if (String(inbox?.name || '') !== ownerInboxName) continue;
    const actualPhone = normalizePhone(inbox?.phone_number || '');
    if (normalizedPhone && actualPhone !== normalizedPhone) {
      throw new Error(`owner_chatwoot_inbox_phone_mismatch:${actualPhone || 'missing'}`);
    }
    return inbox;
  }
  throw new Error('owner_chatwoot_inbox_not_found');
}

async function findOrCreateContact() {
  if (ownerChatwootContactId) {
    return { id: ownerChatwootContactId };
  }
  const search = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/contacts/search`, 'GET', null, {
    q: ownerChatwootSourceId || sourceIdForPhone(recipientPhone),
  });
  if (search.status >= 300) {
    throw new Error(`owner_contact_search_failed:${search.status}`);
  }
  const matches = exactContactMatches(search.body, recipientPhone);
  if (matches.length) {
    ownerChatwootContactId = parseNumber(matches[0]?.id);
    return matches[0];
  }
  const created = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/contacts`, 'POST', {
    inbox_id: null,
    name: compact(input.selected_finca_name || input.client_name || 'Propietario'),
    phone_number: recipientPhone,
  });
  if (created.status >= 300) {
    throw new Error(`owner_contact_create_failed:${created.status}`);
  }
  const payload = created.body?.payload || created.body || {};
  ownerChatwootContactId = parseNumber(payload?.id);
  return payload;
}

async function ensureContactInbox(contactId, inboxId) {
  const existing = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/contacts/${contactId}/contactable_inboxes`);
  if (existing.status >= 300) {
    throw new Error(`owner_contactable_inboxes_failed:${existing.status}`);
  }
  for (const entry of (existing.body?.payload || [])) {
    if (parseNumber(entry?.inbox?.id) === inboxId) {
      ownerChatwootSourceId = compact(entry?.source_id) || ownerChatwootSourceId || sourceIdForPhone(recipientPhone);
      return entry;
    }
  }
  const created = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/contacts/${contactId}/contact_inboxes`, 'POST', {
    inbox_id: inboxId,
    source_id: ownerChatwootSourceId || sourceIdForPhone(recipientPhone),
  });
  if (created.status >= 300) {
    throw new Error(`owner_contact_inbox_create_failed:${created.status}`);
  }
  ownerChatwootSourceId =
    compact(created.body?.source_id) ||
    compact(created.body?.payload?.source_id) ||
    ownerChatwootSourceId ||
    sourceIdForPhone(recipientPhone);
  return created.body?.payload || created.body || {};
}

async function ensureConversation(contactId, inboxId) {
  if (ownerChatwootConversationId) {
    return ownerChatwootConversationId;
  }
  const created = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/conversations`, 'POST', {
    source_id: ownerChatwootSourceId || sourceIdForPhone(recipientPhone),
    inbox_id: inboxId,
    contact_id: contactId,
    status: 'open',
  });
  if (created.status >= 300) {
    throw new Error(`owner_conversation_create_failed:${created.status}`);
  }
  ownerChatwootConversationId = parseNumber(created.body?.id);
  return ownerChatwootConversationId;
}

async function fetchProviderMessageId(conversationId, messageId) {
  if (!conversationId || !messageId) return null;
  const response = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/conversations/${conversationId}`);
  if (response.status >= 300) return null;
  const messages = response.body?.messages || [];
  const matched = messages.find((item) => parseNumber(item?.id) === parseNumber(messageId));
  return compact(matched?.source_id) || null;
}

try {
  if (!recipientPhone) throw new Error('owner_recipient_phone_missing');
  if (!templateName) throw new Error('owner_template_name_missing');
  if (!chatwootBaseUrl || !chatwootAccountId || !chatwootApiToken || chatwootApiToken.startsWith('__')) {
    throw new Error('owner_chatwoot_config_missing');
  }

  const inbox = await findInbox();
  ownerChatwootInboxId = parseNumber(inbox?.id);
  const contact = await findOrCreateContact();
  ownerChatwootContactId = parseNumber(contact?.id) || ownerChatwootContactId;
  await ensureContactInbox(ownerChatwootContactId, ownerChatwootInboxId);
  const conversationId = await ensureConversation(ownerChatwootContactId, ownerChatwootInboxId);

  const sent = await chatwootApi(`/api/v1/accounts/${chatwootAccountId}/conversations/${conversationId}/messages`, 'POST', {
    content: `Hola, te escribimos de De Paseo en Fincas. Tenemos una nueva solicitud de reserva para ${fincaName} del ${fechaInicioText} al ${fechaFinText}. ¿Nos confirmas por favor si está disponible?`,
    message_type: 'outgoing',
    private: false,
    content_type: 'text',
    content_attributes: {},
    template_params: {
      name: templateName,
      category: 'UTILITY',
      language: templateLanguage,
      processed_params: {
        body: {
          '1': fincaName || 'la finca',
          '2': fechaInicioText || 'Sin dato',
          '3': fechaFinText || 'Sin dato',
        },
      },
    },
  });

  responseStatus = sent.status;
  responseBody = sent.body;
  ownerChatwootMessageId = parseNumber(sent.body?.id);
  providerMessageId =
    compact(sent.body?.source_id) ||
    compact(sent.body?.messages?.[0]?.source_id) ||
    compact(await fetchProviderMessageId(conversationId, ownerChatwootMessageId)) ||
    null;

  if (!(responseStatus >= 200 && responseStatus < 300)) {
    errorMessage =
      sent.body?.error?.message ||
      sent.body?.message ||
      'owner_chatwoot_template_send_failed';
  }
} catch (error) {
  errorMessage = error.message || 'owner_chatwoot_template_send_failed';
  responseBody = responseBody || { error: errorMessage };
}

return [
  {
    json: {
      ...input,
      provider_message_id: providerMessageId,
      response_status: responseStatus,
      response_body: responseBody,
      ok: !errorMessage,
      error_message: errorMessage,
      owner_chatwoot_inbox_id: ownerChatwootInboxId,
      owner_chatwoot_contact_id: ownerChatwootContactId,
      owner_chatwoot_source_id: ownerChatwootSourceId || sourceIdForPhone(recipientPhone) || null,
      owner_chatwoot_conversation_id: ownerChatwootConversationId,
      owner_chatwoot_message_id: ownerChatwootMessageId,
      owner_chatwoot_inbox_name: ownerInboxName,
      owner_chatwoot_inbox_phone: ownerInboxPhone,
    },
  },
];

